<script setup lang="ts">
import type { CatalogOverview } from "@moecraft/shared";
const { request, mediaUrl, money } = useStorefrontCatalog();
const { data, pending, error } = await useAsyncData("storefront-home", () => request<CatalogOverview>("/catalog/public"));
const featured = computed(() => data.value?.products.find((product) => product.coverFileId) ?? data.value?.products[0]);
const categories = computed(() => (data.value?.categories ?? []).filter((item) => !item.parentId).slice(0, 6));
const products = computed(() => data.value?.products.slice(0, 8) ?? []);
useSeoMeta({ title: "MoeCraft 手办商城", description: "发现正版手办、同人周边、预售新品与独立创作者作品。", ogImage: () => featured.value?.coverFileId ? mediaUrl(featured.value.coverFileId) : undefined });
</script>

<template>
  <div class="home">
    <StorefrontHeader />
    <main>
      <section class="hero" :class="{ empty: !featured?.coverFileId }" :style="featured?.coverFileId ? { backgroundImage: `url(${mediaUrl(featured.coverFileId)})` } : undefined">
        <div class="shade" />
        <div class="hero-copy"><small>MOECRAFT SELECT</small><h1>{{ featured?.titleZhCn || 'MoeCraft 手办商城' }}</h1><p>{{ featured ? (featured.franchiseName || featured.brandName || featured.storeName) : '正版手办、同人创作与限定周边。' }}</p><b v-if="featured">{{ money(featured.priceAmount, featured.currency) }}</b><div><NuxtLink v-if="featured" :to="`/products/${featured.id}`">查看商品</NuxtLink><NuxtLink to="/catalog" class="secondary">浏览目录</NuxtLink></div></div>
      </section>
      <section class="trust"><span>平台审核商家</span><span>版权信息展示</span><span>库存状态实时同步</span><span>店铺售后直达</span></section>
      <section class="section categories"><header><div><small>SHOP BY CATEGORY</small><h2>按类目发现</h2></div><NuxtLink to="/catalog">全部目录</NuxtLink></header><div v-if="pending" class="category-grid loading"><i v-for="n in 6" :key="n" /></div><div v-else class="category-grid"><NuxtLink v-for="item in categories" :key="item.id" :to="`/categories/${item.slug}`"><span>{{ item.nameZhCn.slice(0, 1) }}</span><div><b>{{ item.nameZhCn }}</b><small>{{ item.nameEnUs || 'MoeCraft collection' }}</small></div><em>{{ item.productCount }} 件</em></NuxtLink></div></section>
      <section class="section products"><header><div><small>NEW ARRIVALS</small><h2>新鲜上架</h2></div><NuxtLink to="/catalog?sort=NEWEST">查看全部</NuxtLink></header><div v-if="pending" class="product-grid loading"><i v-for="n in 4" :key="n" /></div><div v-else-if="error" class="state">商品暂时无法加载。</div><div v-else-if="products.length" class="product-grid"><ProductCard v-for="product in products" :key="product.id" :product="product" /></div><div v-else class="state">第一批精选商品正在准备上架。</div></section>
      <section class="discover"><div><small>EXPLORE</small><h2>从熟悉的作品，找到下一件收藏。</h2></div><nav><NuxtLink v-for="item in data?.franchises.slice(0, 5)" :key="item.id" :to="`/franchises/${item.slug}`"><span>{{ item.nameZhCn }}</span><small>{{ item.nameEnUs || 'MOECRAFT' }}</small><b>{{ item.productCount }}</b></NuxtLink></nav></section>
    </main>
    <StorefrontFooter />
  </div>
</template>

